solution:
function countEvens(nums) {
  // counter starts at zero
  let count = 0;
  // check every element
  for (let i = 0; i < nums.length; i++) {
    // the modulo operator tells us if a number is even
    if (nums[i] % 2 === 0) {
      count++;
    }
  }
  // return the total count of even numbers
  return count;
}

