solution:
function fizzBuzz(n) {
  const result = [];
  // loop from 1 to n inclusive
  for (let i = 1; i <= n; i++) {
    // check 15 first so the combined case isn't swallowed by 3 or 5
    if (i % 15 === 0) {
      result.push('FizzBuzz');
    } else if (i % 3 === 0) {
      result.push('Fizz');
    } else if (i % 5 === 0) {
      result.push('Buzz');
    } else {
      // convert number to string to keep the return type uniform
      result.push(String(i));
    }
  }
  return result;
}

