solution:
function firstDuplicate(nums) {
  // a Set gives O(1) lookup — much faster than a nested loop
  const seen = new Set();
  for (let i = 0; i < nums.length; i++) {
    // if we have seen this number before, its second occurrence is here
    if (seen.has(nums[i])) {
      return nums[i];
    }
    // mark this number as seen before moving on
    seen.add(nums[i]);
  }
  // no number appeared twice
  return -1;
}
